-- Seed Data Script for finAiPro
-- Creates Model table and populates defaults

CREATE TABLE IF NOT EXISTS "Model" (
    "id" TEXT PRIMARY KEY DEFAULT gen_random_uuid(),
    "agentId" TEXT,
    "name" TEXT NOT NULL,
    "architecture" TEXT NOT NULL,
    "accuracy" DOUBLE PRECISION DEFAULT 0,
    "fitness" DOUBLE PRECISION DEFAULT 0,
    "generation" INTEGER DEFAULT 1,
    "modelPath" TEXT,
    "optimizer" TEXT DEFAULT 'adam',
    "score" DOUBLE PRECISION DEFAULT 0,
    "createdAt" TIMESTAMPTZ DEFAULT now() NOT NULL,
    "updatedAt" TIMESTAMPTZ DEFAULT now() NOT NULL
);

-- Template table for default agents
CREATE TABLE IF NOT EXISTS "SeedAgent" (
    "id" TEXT PRIMARY KEY DEFAULT gen_random_uuid(),
    "name" TEXT NOT NULL,
    "type" TEXT NOT NULL,
    "operationType" TEXT NOT NULL,
    "status" TEXT NOT NULL,
    "model" TEXT NOT NULL,
    "modelId" TEXT NOT NULL,
    "asset" TEXT NOT NULL,
    "assetId" TEXT NOT NULL,
    "assetType" TEXT NOT NULL,
    "prompt" TEXT,
    "tvSymbol" TEXT NOT NULL,
    "provider" TEXT NOT NULL,
    "timeframe" TEXT NOT NULL,
    "candleCount" INTEGER NOT NULL,
    "sources" TEXT,
    "predictionType" TEXT,
    "market" TEXT
);

DELETE FROM "SeedAgent";

-- Ensure Agent table has all columns required by Prisma and triggers
ALTER TABLE "Agent" ADD COLUMN IF NOT EXISTS "predictionType" TEXT DEFAULT 'swing';
ALTER TABLE "Agent" ADD COLUMN IF NOT EXISTS "isMultiPrediction" BOOLEAN DEFAULT false;
ALTER TABLE "Agent" ADD COLUMN IF NOT EXISTS "multiAssets" TEXT DEFAULT '';


-- Sample Models (50 models)
DELETE FROM "Model";

-- Trigger to initialize new user profiles with default agents
CREATE OR REPLACE FUNCTION initialize_user_agents()
RETURNS TRIGGER AS $$
BEGIN
    SELECT NEW."id", name, type, "operationType", status, model, "modelId", asset, "assetId", "assetType", prompt, tvSymbol, provider, timeframe, "candleCount", sources, "predictionType", false, ''
    FROM "SeedAgent";
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS tr_initialize_user_agents ON "Profile";
CREATE TRIGGER tr_initialize_user_agents
AFTER INSERT ON "Profile"
FOR EACH ROW
EXECUTE FUNCTION initialize_user_agents();